code = """import json\nimport re\n\nwith open(locals()['var_function-call-2241076992410809533'], 'r') as f:\n    civic_docs = json.load(f)\n\nprojects_data = []\n\nfor doc in civic_docs:\n    text = doc['text']\n\n    # Regex to find project blocks. A project block starts with a project name and contains updates/schedule/description.\n    # It ends before the next project name or a major section heading (like 'Capital Improvement Projects').\n    # Using re.DOTALL to allow . to match newlines.\n    project_block_pattern = re.compile(r'^([A-Z][a-zA-Z0-9 \\-&,.''\\\\]+? (?:Project|Plan))\\n\\n(?:\\(cid:190\\) (?:Updates|Project Schedule|Project Description):.*?\\n(?=[A-Z][a-zA-Z0-9 \\-&,.''\\\\]+? (?:Project|Plan)|Capital Improvement Projects|Disaster Recovery Projects|$))' , re.DOTALL | re.MULTILINE)\n\n    for match in project_block_pattern.finditer(text):\n        full_block = match.group(0) # Get the entire matched block\n        project_name = match.group(1).strip()\n        status = \"unknown\"\n        topic = \"general\"\n\n        # Check for FEMA/emergency keywords to assign topic\n        if re.search(r'emergency|FEMA', full_block, re.IGNORECASE) or re.search(r'emergency|FEMA', project_name, re.IGNORECASE):\n            topic = \"emergency/FEMA\"\n\n        # Infer status from the block content\n        if re.search(r'completed', full_block, re.IGNORECASE):\n            status = \"completed\"\n        elif re.search(r'construction|begin construction', full_block, re.IGNORECASE):\n            status = \"construction\"\n        elif re.search(r'design|preliminary design|FEMA/CalOES approval', full_block, re.IGNORECASE):\n            status = \"design\"\n        elif re.search(r'not started', full_block, re.IGNORECASE):\n            status = \"not started\"\n\n        # Add project to data if it matches criteria\n        if topic == \"emergency/FEMA\":\n            projects_data.append({\"Project_Name\": project_name, \"status\": status, \"topic\": topic})\n\n    # Also check for projects explicitly mentioned in context that might not fit the block pattern\n    # Outdoor Warning Signs\n    if re.search(r'Outdoor Warning Signs', text) and re.search(r'emergency', text, re.IGNORECASE):\n        projects_data.append({\"Project_Name\": \"Outdoor Warning Signs\", \"status\": \"design\", \"topic\": \"emergency\"})\n    \n    # Latigo Canyon Road Retaining Wall Repair Project\n    if re.search(r'Latigo Canyon Road Retaining Wall Repair Project', text) and re.search(r'FEMA/CalOES approval', text):\n        projects_data.append({\"Project_Name\": \"Latigo Canyon Road Retaining Wall Repair Project\", \"status\": \"design\", \"topic\": \"FEMA\"})\n\n    # City Traffic Signals Backup Power\n    traffic_signals_match = re.search(r'City Traffic Signals Backup Power\n\n\(cid:190\) Project Description:(.*?)\n\n\(cid:190\) Updates:(.*?)\n\n\(cid:190\) Project Schedule:(.*?)(?=\n\n.+?$)', text, re.DOTALL)\n    if traffic_signals_match:\n        description = traffic_signals_match.group(1)\n        updates = traffic_signals_match.group(2)\n        if re.search(r'emergency', description, re.IGNORECASE) or re.search(r'emergency', updates, re.IGNORECASE):\n            projects_data.append({\"Project_Name\": \"City Traffic Signals Backup Power\", \"status\": \"preliminary design\", \"topic\": \"emergency\"})\n\n\n# Remove duplicates\nunique_projects = []\nseen_projects = set()\nfor project in projects_data:\n    project_tuple = (project[\'Project_Name\'], project[\'status\'], project[\'topic\'])\n    if project_tuple not in seen_projects:\n        unique_projects.append(project)\n        seen_projects.add(project_tuple)\n\n\nprint(\"__RESULT__:\")\nprint(json.dumps(unique_projects))"""

env_args = {'var_function-call-16338752333912652679': ['civic_docs'], 'var_function-call-2241076992410809533': 'file_storage/function-call-2241076992410809533.json'}

exec(code, env_args)
